var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"신분은 확인되었지만, 죄송합니다.","JPN":"身元は確認できましたが、大変申し訳ありません。","ENG":"Your identification was confirmed, but we are deeply sorry.","TWN":"已經確認過您的身份，但是很抱歉，"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"지금은 시니어님께서 만나시기 어려운 상황이셔서요.","JPN":"現在はシニアとお会いになれる状況ではありません。","ENG":"The Senior is not able to take any visitors.","TWN":"Senior現在沒辦法見您。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이유라도 들을 수 있겠나?","JPN":"理由ぐらいは聞かせてくれないか？","ENG":"May we at least hear why?","TWN":"我能知道原因嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그쪽에서 만나기 싫어하던가?","JPN":"会いたくないとでも言っていたのか？","ENG":"He didn't want to meet us?","TWN":"是他不想見我嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"국제 수배된 테러리스트 검거 현장을 지휘 중이십니다.","JPN":"国際手配になったテロリストの検挙現場を指揮しておられます。","ENG":"He is currently in command of the apprehension of an internationally wanted terrorist.","TWN":"他正在現場指揮逮捕國際通緝的恐怖分子。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"작전이 종결되기 전까지는 아무래도 연락하기 어려우실 것 같아요.","JPN":"作戦が終結するまでは、連絡を取るのは難しいと思われます。","ENG":"It will be difficult for him to contact you until the end of operations.","TWN":"作戰結束之前，可能都沒辦法聯繫到他。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"아뇨. 그런 기색은 없었습니다.","JPN":"いいえ。そのようには見えませんでした。","ENG":"No. That did not seem to be the case.","TWN":"不，沒有那個意思。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이번 외근도 갑작스럽게 연락을 받고 일정을 조정하셨어요.","JPN":"今度の外勤も、急に連絡があって日程を調整されたのです。","ENG":"He revised his schedule only after receiving an urgent call.","TWN":"這次出勤也是因為突然接到通知，才臨時調整行程。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"혹시 샤레이드에서는 어디에서 머무실지 정해 두셨을까요?","JPN":"シャレードではどちらにお泊りになるか、お決まりでしょうか？","ENG":"Could you let us know where you will be staying in Charade?","TWN":"請問是否已經在查雷德預好下榻的地點呢？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"연락처를 남겨 주시면 돌아오시는 대로 연락드리겠습니다.","JPN":"連絡先を教えていただけましたら、戻り次第ご連絡いたします。","ENG":"If you leave your contact information, we will reach out as soon as he returns.","TWN":"還是請您留下聯繫方式，等他回來我就馬上聯繫您。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……자리를 비웠다고?","JPN":"……席を外してるって？","ENG":"…He's away now?","TWN":"……不在？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이유야 어쨌든 문전박대 당한 셈이네.","JPN":"理由はともかく、門前払いを食らったわけだね。","ENG":"Whatever the reason, I guess we were just turned away.","TWN":"不管是什麼原因，這樣應該算吃了閉門羹吧？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"소명 기회를 주기 싫어서일 수도 있지.","JPN":"弁明する機会を与えたくないからかもしれないな。","ENG":"Perhaps he does not want to offer me a chance to explain.","TWN":"也有可能是不想給我解釋的機會。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"너무 걱정할 것 없네, 미나 양.","JPN":"あまり心配するな、ミナ君。","ENG":"No need to worry, Mina.","TWN":"用不著太擔心，米娜。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그건 너무 치졸한 방식 아니야?","JPN":"それ、ズルすぎない？","ENG":"That's petty.","TWN":"這麼幼稚？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"자기들은 느닷없이 들이닥쳐서 이래라저래라 하더니….","JPN":"自分たちはいきなり押し寄せて来て、あれこれ命令したくせに……","ENG":"After all, they're the ones who barged in and ordered us around...","TWN":"明明是他們自己突然闖進來指手畫腳……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……딱히, 걱정하는 건 아니야.","JPN":"……別に、心配してないよ。","ENG":"...I'm not worried.","TWN":"……我是沒有很擔心。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};